mapper.select:
SELECT COALESCE((
                    SELECT COUNT(1)
                    FROM mall_order
                    WHERE is_deleted = 0
                      AND create_time >= #{startTime}
                      AND create_time < #{endTime}
                ), 0) AS createdOrderCount,
       COALESCE((
                    SELECT COUNT(1)
                    FROM mall_order
                    WHERE is_deleted = 0
                      AND create_time >= #{startTime}
                      AND create_time < #{endTime}
                      AND paid = 1
                ), 0) AS paidOrderCount,
       COALESCE((
                    SELECT COUNT(1)
                    FROM mall_order
                    WHERE is_deleted = 0
                      AND create_time >= #{startTime}
                      AND create_time < #{endTime}
                      AND order_status = 'PENDING_PAYMENT'
                ), 0) AS pendingPaymentOrderCount,
       COALESCE((
                    SELECT COUNT(1)
                    FROM mall_order
                    WHERE is_deleted = 0
                      AND create_time >= #{startTime}
                      AND create_time < #{endTime}
                      AND order_status IN ('CANCELLED', 'EXPIRED')
                ), 0) AS closedOrderCount

SELECT COALESCE((
                    SELECT ROUND(AVG(TIMESTAMPDIFF(SECOND, apply_time, audit_time)) / 3600, 1)
                    FROM mall_after_sale
                    WHERE is_deleted = 0
                      AND apply_time >= #{startTime}
                      AND apply_time < #{endTime}
                      AND audit_time IS NOT NULL
                ), 0) AS averageAuditHours,
       COALESCE((
                    SELECT ROUND(AVG(TIMESTAMPDIFF(SECOND, apply_time, complete_time)) / 3600, 1)
                    FROM mall_after_sale
                    WHERE is_deleted = 0
                      AND apply_time >= #{startTime}
                      AND apply_time < #{endTime}
                      AND complete_time IS NOT NULL
                ), 0) AS averageCompleteHours,
       COALESCE((
                    SELECT COUNT(1)
                    FROM mall_after_sale
                    WHERE is_deleted = 0
                      AND after_sale_status = 'PENDING'
                      AND apply_time >= #{startTime}
                      AND apply_time < #{endTime}
                      AND apply_time < DATE_SUB(NOW(), INTERVAL 24 HOUR)
                ), 0) AS overdueAuditCount,
       COALESCE((
                    SELECT COUNT(1)
                    FROM mall_after_sale
                    WHERE is_deleted = 0
                      AND after_sale_status IN ('APPROVED', 'PROCESSING')
                      AND apply_time >= #{startTime}
                      AND apply_time < #{endTime}
                      AND apply_time < DATE_SUB(NOW(), INTERVAL 72 HOUR)
                ), 0) AS overdueCompleteCount
